import{_ as c,y as e,a as i,o as g,ag as r,D as o,g as t,I as a}from"./chunks/framework.RVu0gECZ.js";const b=JSON.parse('{"title":"Tạo hóa đơn","description":"","frontmatter":{},"headers":[],"relativePath":"orders/create-invoice.md","filePath":"orders/create-invoice.md","lastUpdated":1775735616000}'),s={name:"orders/create-invoice.md"};function p(l,n,d,u,m,v){const h=e("ImagePopup");return g(),i("div",null,[n[0]||(n[0]=r('<h1 id="tao-hoa-đon" tabindex="-1">Tạo hóa đơn <a class="header-anchor" href="#tao-hoa-đon" aria-label="Permalink to &quot;Tạo hóa đơn&quot;">​</a></h1><p>Từ đây, bạn có thể tạo hóa đơn cho đơn hàng và xác nhận đơn hàng của khách hàng bằng cách nhấp vào <strong>Hóa đơn</strong>.</p><p>Quản trị viên có thể kiểm tra chi tiết nhập số lượng vào hóa đơn sau đó nhấp vào Hóa đơn.</p><p>Hóa đơn được sử dụng để xác nhận giao dịch thương mại điện tử và cung cấp xác nhận đơn hàng chi tiết cho khách hàng.</p><p>Điều đó có nghĩa là một số người bán B2B có thể cung cấp tín dụng: đơn hàng sẽ được đặt trước và hóa đơn sẽ được gửi sau để yêu cầu thanh toán.</p><p>Một tài liệu thương mại được chia thành từng khoản ghi lại các sản phẩm hoặc dịch vụ được giao cho khách hàng, tổng số tiền đến hạn và phương thức thanh toán ưu tiên.</p><p>Người bán có thể gửi hóa đơn giấy hoặc hóa đơn điện tử cho khách hàng. Nó là một tài liệu được sử dụng để ghi lại giao dịch giữa người mua và người bán.</p><p>Nó chứa thông tin về mặt hàng và giá của nó, các khoản thuế liên quan đến nó, v.v.</p>',8)),o(h,{src:"/images/orders/invoice.png",alt:"Invoice"}),n[1]||(n[1]=t("p",null,[a("Sau khi tạo trạng thái Đơn hàng hóa đơn sẽ tự động chuyển từ "),t("strong",null,"Đang chờ"),a(" sang "),t("strong",null,"Đang xử lý")],-1)),o(h,{src:"/images/orders/invoiceSubmit.png",alt:"Invoice Submit"}),n[2]||(n[2]=t("p",null,[a("Bằng cách làm theo các bước trên, bạn có thể dễ dàng tạo "),t("strong",null,"Hóa đơn"),a(" trong VNS.")],-1))])}const k=c(s,[["render",p]]);export{b as __pageData,k as default};
